import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;

public class Main {

    static class Student {
        String name;
        int grade;

        Student(String name, int grade) {
            this.name = name;
            this.grade = grade;
        }
    }

    public static void main(String[] args) {
        ArrayList<Student> students = new ArrayList<>();
        students.add(new Student("Ahmet", 85));
        students.add(new Student("Ayse", 92));
        students.add(new Student("Mehmet", 67));
        students.add(new Student("Zeynep", 78));
        students.add(new Student("Can", 55));

        System.out.println("Tum ogrenciler:");
        for (Student s : students) {
            System.out.println(s.name + ": " + s.grade);
        }

        // Yeni ogrenci ekleme
        students.add(new Student("Elif", 88));
        System.out.println("\nElif eklendi. Toplam ogrenci: " + students.size());

        // Not güncelleme
        for (Student s : students) {
            if (s.name.equals("Mehmet")) {
                s.grade = 70;
                System.out.println("\nMehmet'in notu guncellendi: " + s.grade);
            }
        }

        // Geçenler / kalanlar sayısı
        int passing = 0, failing = 0;
        for (Student s : students) {
            if (s.grade >= 60) passing++;
            else failing++;
        }

        System.out.println("\nGecen ogrenci sayisi: " + passing);
        System.out.println("Kalan ogrenci sayisi: " + failing);

        // Sıralama (en yüksekten en düşüğe)
        students.sort(Comparator.comparingInt((Student s) -> s.grade).reversed());

        System.out.println("\nNot siralamasi (yuksekten alcaga):");
        for (Student s : students) {
            System.out.println(s.name + ": " + s.grade);
        }

        // Ortalama
        double total = 0;
        for (Student s : students) total += s.grade;
        System.out.printf("\nSinif ortalamasi: %.2f%n", total / students.size());
    }
}
